Future<DriverFinishTripCommitResultState> _commitFinishTrip(
  BuildContext context,
  User user,
  _DriverActiveTripContext tripContext,
) async {
  final stopwatch = Stopwatch()..start();
  final uidPrefix = user.uid.length <= 8 ? user.uid : user.uid.substring(0, 8);
  final deviceId = '${_devicePlatformKey()}_$uidPrefix';
  final idempotencyKey = _buildTripActionIdempotencyKey(
    action: 'finish_trip',
    subject: tripContext.tripId,
  );
  final execution = await _executeDriverFinishTripSyncUseCase.execute(
    DriverFinishTripSyncCommand(
      ownerUid: user.uid,
      tripId: tripContext.tripId,
      expectedTransitionVersion: tripContext.transitionVersion,
      deviceId: deviceId,
      idempotencyKey: idempotencyKey,
    ),
  );
  final handlingPlan = _planDriverFinishTripCommitHandlingUseCase.execute(
    execution,
  );
  if (handlingPlan.shouldStopTrackingServices) {
    await _syncDriverLocationForegroundService(shouldRun: false);
    await _syncIosSilentKillWatchdog(shouldRun: false);
  }
  if (!context.mounted) {
    if (handlingPlan.shouldTrackWhenUnmounted) {
      _trackFinishTripCommitTelemetry(
        stopwatch: stopwatch,
        tripId: tripContext.tripId,
        handlingPlan: handlingPlan,
      );
    }
    return handlingPlan.unmountedResultState;
  }
  _showInfo(context, _resolveFinishTripCommitMessage(handlingPlan));
  _trackFinishTripCommitTelemetry(
    stopwatch: stopwatch,
    tripId: tripContext.tripId,
    handlingPlan: handlingPlan,
  );
  return handlingPlan.mountedResultState;
}

Future<void> _handleSendDriverAnnouncement(
  BuildContext context, {
  String? routeIdOverride,
  String? routeNameOverride,
}) async {
  final user = _authCredentialGateway.currentUser;
  if (user == null) {
    if (context.mounted) {
      _showInfo(context, CoreErrorFeedbackTokens.sessionMissingSignInAgain);
    }
    return;
  }

  final normalizedRouteIdOverride = _nullableParam(routeIdOverride);
  final normalizedRouteNameOverride = _nullableParam(routeNameOverride);
  final routeContext = normalizedRouteIdOverride == null
      ? await _resolvePrimaryDriverRouteContext(user.uid)
      : _DriverRouteContext(
